120	\begin{theorem}
121	[Cotangent exact sequence for a composition]
122	  \label{thm:cotangent_exact_sequence}
123	  \lean{AlgebraicGeometry.Scheme.cotangent_exact_sequence}
124	  \uses{def:relative_kaehler_sheaf, def:universal_derivation, def:cotangent_alpha, def:cotangent_beta, lem:cotangent_exact_structure}
125	  For schemes $X \xrightarrow{f} Y \xrightarrow{g} S$, there is an exact sequence of quasi-coherent $\struct{X}$-modules
126	  \[
127	    f^*\Omega_{Y/S} \;\xrightarrow{\;\alpha\;}\; \Omega_{X/S} \;\xrightarrow{\;\beta\;}\;
128	      \Omega_{X/Y} \;\longrightarrow\; 0,
129	  \]
130	  with $\alpha$ and $\beta$ as above. It follows by bundling the three claims of Lemma~\ref{lem:cotangent_exact_structure}.
131	\end{theorem}
