143	\begin{corollary}\leanok
144	[Cotangent space at a section]
145	  \label{cor:cotangent_at_section}
146	  \lean{AlgebraicGeometry.Scheme.cotangent_at_section}
147	  \uses{thm:smooth_iff_locally_free_omega}
148	  If $f \colon X \to S$ is smooth of relative dimension $n$ and $s \colon S \to X$ is a section of $f$, then the cotangent space $s^*\Omega_{X/S}$ is a locally free $\struct{S}$-module of rank $n$. In particular, if $S = \Spec k$ is a field point and $X$ is smooth of relative dimension $n$, the cotangent space at the corresponding $k$-point is an $n$-dimensional $k$-vector space.
149	\end{corollary}
